}}];

// Mirrors score_lead_v2() from backend/integrations/lead_scorer.py
const lead = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
if (!lead || !lead.id) return [{ json: { skipped: true, reason: 'lead_not_found' } }];
let score = 0;
const reasons = [];
const BASIC = ['calendly','squarespace','wix','square'];
const ADVANCED = ['mindbody','vagaro','fresha','jane_app','boulevard','zenoti'];
if (!lead.has_website && !lead.website) { score += 20; reasons.push('no website'); }
if (!lead.has_booking_system && !lead.has_online_booking) { score += 25; reasons.push('no online booking'); }
if (!lead.has_chatbot) { score += 15; reasons.push('no AI/chatbot'); }
const rc = lead.review_count || 0;
if (rc < 50) { score += 15; reasons.push('only ' + rc + ' reviews'); }
const rating = lead.google_rating || 0;
if (rating > 0 && rating < 4.0) { score += 10; reasons.push(rating + '★ rating'); }
if (lead.email || lead.instagram_email) { score += 10; reasons.push('has email'); }
if (lead.phone) { score += 5; reasons.push('has phone'); }
const bp = lead.booking_platform || '';
if (BASIC.includes(bp)) { score += 15; reasons.push('uses ' + bp + ' (easy upgrade)'); }
else if (ADVANCED.includes(bp)) { score -= 10; reasons.push('uses ' + bp + ' (harder sell)'); }
if (!lead.instagram_username && !lead.instagram) { score += 10; reasons.push('no Instagram'); }
else if ((lead.instagram_followers || 0) < 500) { score += 8; reasons.push('low Instagram followers'); }
if (lead.instagram_email) { score += 8; reasons.push('email in Instagram bio'); }
if (!lead.facebook_page_name) { score += 5; reasons.push('no Facebook page'); }
if (!lead.linkedin_company_url) { score += 5; reasons.push('no LinkedIn'); }
score = Math.min(score, 100);
const tier = score >= 75 ? 'A' : score >= 50 ? 'B' : 'C';
return [{ json: { lead_id: lead.id, score, tier, score_reason: reasons.join(', ') } }];
